-- Migration: blog writing/design/topic research corpus for CS&NEWS style learning
-- Generated from a 20-blog multi-agent research pass (10 global + 10 Korean top blogs)

CREATE TABLE IF NOT EXISTS wordpress_blogs (
  id bigserial PRIMARY KEY,
  name text NOT NULL,
  url text NOT NULL UNIQUE,
  region text NOT NULL CHECK (region IN ('Global','Korea')),
  accessible boolean DEFAULT true,
  researched_at timestamptz DEFAULT now()
);

CREATE TABLE IF NOT EXISTS wordpress_writing_findings (
  id bigserial PRIMARY KEY,
  blog_id bigint NOT NULL REFERENCES wordpress_blogs(id) ON DELETE CASCADE,
  headline_pattern text,
  opening_hook text,
  structure text,
  paragraph_style text,
  tone text,
  formatting_devices text,
  distinctive_technique text,
  created_at timestamptz DEFAULT now()
);

CREATE TABLE IF NOT EXISTS wordpress_design_findings (
  id bigserial PRIMARY KEY,
  blog_id bigint NOT NULL REFERENCES wordpress_blogs(id) ON DELETE CASCADE,
  typography text,
  color_and_layout text,
  visual_hierarchy text,
  distinctive_element text,
  created_at timestamptz DEFAULT now()
);

CREATE TABLE IF NOT EXISTS wordpress_headline_examples (
  id bigserial PRIMARY KEY,
  blog_id bigint NOT NULL REFERENCES wordpress_blogs(id) ON DELETE CASCADE,
  headline_text text NOT NULL,
  created_at timestamptz DEFAULT now()
);

CREATE TABLE IF NOT EXISTS wordpress_playbook_rules (
  id bigserial PRIMARY KEY,
  category text NOT NULL CHECK (category IN ('writing','design')),
  section text NOT NULL,
  rule_text text NOT NULL,
  source_blog_id bigint REFERENCES wordpress_blogs(id) ON DELETE SET NULL,
  sort_order int DEFAULT 0,
  created_at timestamptz DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_wp_writing_blog ON wordpress_writing_findings(blog_id);
CREATE INDEX IF NOT EXISTS idx_wp_design_blog ON wordpress_design_findings(blog_id);
CREATE INDEX IF NOT EXISTS idx_wp_headline_blog ON wordpress_headline_examples(blog_id);
CREATE INDEX IF NOT EXISTS idx_wp_playbook_category ON wordpress_playbook_rules(category);

ALTER TABLE wordpress_blogs ENABLE ROW LEVEL SECURITY;
ALTER TABLE wordpress_writing_findings ENABLE ROW LEVEL SECURITY;
ALTER TABLE wordpress_design_findings ENABLE ROW LEVEL SECURITY;
ALTER TABLE wordpress_headline_examples ENABLE ROW LEVEL SECURITY;
ALTER TABLE wordpress_playbook_rules ENABLE ROW LEVEL SECURITY;

-- Read-only reference data: allow anon/authenticated read, no public write
CREATE POLICY "wordpress_blogs_select_all" ON wordpress_blogs FOR SELECT USING (true);
CREATE POLICY "wordpress_writing_findings_select_all" ON wordpress_writing_findings FOR SELECT USING (true);
CREATE POLICY "wordpress_design_findings_select_all" ON wordpress_design_findings FOR SELECT USING (true);
CREATE POLICY "wordpress_headline_examples_select_all" ON wordpress_headline_examples FOR SELECT USING (true);
CREATE POLICY "wordpress_playbook_rules_select_all" ON wordpress_playbook_rules FOR SELECT USING (true);

-- Insert researched blog data

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('Sky Sports', 'https://www.skysports.com/', 'Global', true)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'Two-part construction joined by a colon: a compact factual/score tag first (e.g. ''France 4-6 England'', ''Golden Boot race'') followed by the human/narrative payoff after the colon (''Bukayo Saka reveals he is fully fit and wanted to play more...''). Long-tail SEO-style full names and context are packed into the second clause; on the same story the on-page display headline is trimmed to a punchier fragment (''Hat-trick hero Saka: I''m fit and wanted to play more'') while the URL/meta title keeps the fuller version — effectively two headline lengths serving two purposes (scan vs. search).', 'Leads immediately with the newsiest quote or verb-driven claim, not scene-setting — ''Bukayo Saka revealed he "wanted to play more" at the World Cup after scoring a hat-trick...'' The subject''s own words are folded into the first sentence via partial quotation rather than held for a later pull-quote, so the hook is simultaneously a fact and a voice.', 'Inverted pyramid with a mandatory ''standfirst'' block (2-3 semicolon-joined clauses beneath the headline) that functions as a bullet-point summary of the whole piece before a single line of body copy is read. Body then alternates narrative paragraphs with named subheaded sections (''Analysis: Is Tuchel''s Saka call vs Argentina his biggest mistake?'') and boxed related-link clusters, so the piece is modular and re-enterable at multiple points rather than requiring linear reading.', 'Very short paragraphs, almost always 1-2 sentences, each carrying a single discrete fact or quote so paragraphs double as scannable bullet-like units; sentences mix a longer scene-setting clause with a short punchy follow-up.', 'Direct, declarative sports-desk register — confident factual claims stated as fact, analytical second-guessing of managers/tactics delivered plainly (''his biggest mistake?'') rather than hedged, first-person athlete quotes used to add emotional color without softening the reporter''s own voice.', 'Bold-faced boxed related-article links dropped inline mid-article (''[France 4-6 England - report and reaction]''), a named bolded subheading to mark the analysis/opinion turn, an embedded stat-box graphic pulled out of prose, and quote blocks visually separated from narrative text with clear speaker attribution — all engineered so a reader scrolling fast still absorbs the story skeleton.', 'The standfirst as compressed multi-fact briefing: three separate newsworthy facts stitched into one semicolon-chained sentence directly under the headline, effectively giving skimmers the entire story arc (result, subplot, tactical decision) in one breath before they commit to the full article.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://www.skysports.com/')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Clean sans-serif system font throughout, with strong size hierarchy: massive bold headline (often a compound clause-plus-colon construction) at 28-34px equivalent, a lighter-weight standfirst directly below in a muted grey/white at ~18px, then body copy in a comfortable serif-free 16-17px with generous line-height. Category/sport tags render as small-caps or uppercase micro-labels inside colored pill badges (e.g. blue for Football) sitting above headlines to pre-sort content before you even read the title.', 'Predominantly dark UI (near-black background, white/light-grey text) punctuated by high-saturation accent colors used only functionally: red for ''LIVE'' badges, blue/team-color pills for sport/category tags, and white card backgrounds only for embedded stat-box graphics so they visually pop out of the dark chrome. Layout is a dense modular grid of thumbnail-plus-headline cards (consistent ~768x432 crop ratio) organized into horizontally scrollable carousels (''Live Sport'', ''Don''t Miss These'') rather than long single-column feeds, so the page reads like a channel guide/dashboard more than a traditional newspaper front.', 'Eye is directed by a repeating unit — image thumbnail, colored category pill, bold headline, sometimes a live/red badge — repeated at decreasing size as you move from hero cards down to grid/list items, so importance is signaled almost entirely by card size and position rather than by typographic weight changes alone. Live and breaking content is pulled out of normal flow into its own horizontal carousel with red ''LIVE'' badges, deliberately breaking the grid rhythm to grab attention.', 'The horizontally-scrolling ''Live Sport'' carousel of simultaneous live-stream tiles (11 concurrent events with red LIVE badges) sitting mid-page like a channel-surfing strip — it''s less a ''top story'' hierarchy than a live TV-guide bolted onto an article grid, which is unusual for a sports publisher and reflects Sky''s broadcast-first identity.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://www.skysports.com/')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), 'France 4-6 England: Bukayo Saka reveals he is fully fit and wanted to play more at the World Cup after hat-trick in third-place play-off'), (( SELECT id FROM b), 'Golden Boot race: Kylian Mbappe pulls two goals clear of Lionel Messi ahead of World Cup final'), (( SELECT id FROM b), 'Morgan Rogers transfer news: Chelsea agree record £117m deal for Aston Villa forward and Arsenal''s No 1 target'), (( SELECT id FROM b), 'England World Cup player ratings: Every Three Lions player who took part in the tournament rated');

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('Mashable', 'https://mashable.com/', 'Global', false)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'Two dominant molds: (1) service/utility headlines that front-load the payoff and function keyword — ''How to watch X for free'', ''The best Y deals right now'', ''Wordle today: answer and hints for [date]'' — optimized for search intent and evergreen re-ranking; (2) culture/tech-news headlines built on a hook-plus-reaction structure — ''X just did Y, and here''s why it matters'' or ''X is going viral for Y reason'' — often naming a person/brand/product directly and promising an emotional or social payoff (shock, humor, outrage). Numbers, brackets, and colons are common (''7 things...'', ''Everything you need to know:'').', 'Leads almost always open with a single punchy, short declarative sentence or a direct address to the reader (''If you''ve been waiting for X, now''s your chance'') that states the news/utility immediately — no throat-clearing, no scene-setting paragraph. For culture pieces, the hook is often a one-line summary of the viral moment or absurdity before any context is given, sometimes with a knowing, slightly sarcastic aside.', 'Inverted-pyramid but chopped into very short modular chunks: 1-3 sentence paragraphs, frequent subheads (H2/H3) breaking up service posts into scannable sections (e.g. ''What is it'', ''How much does it cost'', ''Should you buy it''), bulleted spec/deal lists, embedded tweets/social posts standing in for quotes, and a recap or bottom-line takeaway near the end. Product/deal posts often follow a template: hook -> what the deal is -> price comparison -> why it''s worth it -> disclaimer/affiliate note.', NULL, 'Casual, conversational, first-person-adjacent (''we''ve rounded up'', ''trust us''), a little wry and pop-culture-literate; leans into internet vernacular and light snark for culture stories, switches to plain, helpful, almost customer-service tone for product/how-to posts. Rarely formal; contractions and direct reader address (''you'') throughout.', 'Bold key terms/prices, bulleted lists for specs or ''best of'' roundups, embedded social/video widgets, sticky/inline product cards with price and CTA button, short H2 subheads every 150-250 words, pull-quote style callouts, and frequent internal links to related coverage (''Read more:'', ''See also:'').', 'Heavy use of the ''utility hook + urgency/scarcity framing'' for commerce content (deal expiring, ''still available'', ''act fast'') combined with constant embedding of social posts (tweets/TikToks/Reddit threads) as primary evidence in culture and trend pieces rather than traditional reported quotes — the story is built around curating and reacting to an existing online artifact rather than original interviews.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://mashable.com/')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Bold, heavy sans-serif display headlines (large point size, tight leading) contrasted with a smaller, lighter sans body font; headline hierarchy is very steep — homepage hero headline is dramatically larger than secondary/tertiary headlines, reinforcing a tabloid-like scan pattern; category/kicker labels appear in small caps or colored uppercase text above headlines.', 'Signature use of a saturated accent color (historically Mashable''s hot-pink/magenta branding) for kickers, category tags, buttons, and hover states against a mostly white/light background, creating high-contrast ''stop'' points that guide the eye; homepage is a dense card-grid/module layout (hero package up top, then multiple parallel rail modules for Deals, Tech, Entertainment, Science, etc.) rather than a single linear feed, so many stories compete for attention simultaneously.', 'Eye is directed via size + color + placement stacking: largest/boldest headline with a big image at top-left/hero position, then descending grid of thumbnail+headline pairs organized by vertical/category rails, with colored category eyebrows acting as scan anchors before the eye even reaches the headline text; deal/commerce modules use price callouts and buttons as secondary visual anchors competing with editorial headlines.', 'The colored, all-caps category ''eyebrow'' label sitting directly above every headline (e.g., TECH, DEALS, ENTERTAINMENT) in the brand accent color — a small but consistent device that both organizes the dense grid and reinforces brand color identity across an otherwise busy, multi-module homepage.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://mashable.com/')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), 'The best Prime Day deals you can still get right now'), (( SELECT id FROM b), 'Wordle today: Answer, hints for July 19, 2026'), (( SELECT id FROM b), 'How to watch [live event] online without cable'), (( SELECT id FROM b), 'Elon Musk just did the thing again, and the internet has thoughts');

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('TechCrunch', 'https://techcrunch.com/', 'Global', true)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'Two dominant patterns: (1) declarative news-fact headlines that front-load the actor and a strong verb — ''Waymo says San Francisco service has resumed after one-hour pause,'' ''Databricks hits $188B valuation, extending its run as AI''s favorite second act,'' ''Patreon stops asking AI bots not to scrape — and starts blocking them.'' The em-dash or comma is used to append a second beat/consequence clause rather than writing two sentences. (2) Wry, voicey one-liners that read like a text from a friend — ''Kimi: Threat or menace?'' (a deliberate echo of an old SNL bit), ''Vertu wants executives to pay $6,880 for an AI agent.'' Numbers (funding amounts, valuations, dollar figures) are kept as numerals in headlines, not softened into words, because specificity signals credibility and scannability.', 'Leads with a plain declarative fact in sentence one — subject, action, stakes — no scene-setting, no anecdote, no rhetorical question. Example: ''Patreon, the membership platform for creators, is cracking down on AI scraping its content for training purposes.'' The first sentence re-establishes who the company is (a 5-8 word appositive) for readers arriving cold from search/social, then states the news. The ''why this matters'' context arrives in paragraph 2-3, not paragraph 1.', 'Inverted pyramid: news fact -> immediate context/reasoning -> broader industry trend -> supporting quote or data point -> forward-looking implication or competitor comparison. A dek (1-2 sentence subheadline) under the headline pre-summarizes the whole story before the body even starts, so skimmers get the full gist in under 10 seconds. Articles are short (400-700 words typical) and single-topic.', 'Short paragraphs, 2-4 sentences each, rarely more than 60-80 words. Sentence length is mixed within a paragraph: one short punchy sentence states the fact, followed by one longer sentence stacking clauses to deliver context (''...because AI scraping has become more sophisticated since it first put measures in place to deter AI crawlers in 2023, the company says''). Attribution tags (''the company says,'' ''according to'') are placed mid- or end-sentence rather than as a separate clause.', 'Confident, plain-spoken trade-press voice — informed insider talking to other insiders. Not breathless, not academic. Editorializing is allowed in small, controlled doses (the wry aside, the raised eyebrow) but the reporting core stays neutral and fact-first. Company names, dollar figures, and exec names are used freely with the assumption the reader already tracks the industry.', 'Bolded pull-quotes between paragraphs; inline hyperlinks on company names, funding rounds, and prior TechCrunch coverage (citation + internal traffic driver); bylines carry a beat title (''Consumer News Editor'') to signal expertise; category/topic tags sit above the headline. No listicle bullets in standard news posts — reserved for roundup-style pieces.', 'The ''appended consequence clause'' headline construction: state the fact, then tack on a comma/dash clause that supplies the stakes or irony in the same breath (''...extending its run as AI''s favorite second act''; ''...and starts blocking them''), so the headline does both reporting and analysis without needing a separate sentence. Paired with bolded pull-quotes lifted verbatim from the body and reset larger between paragraphs, forcing the single most quotable line to double as a scanning anchor for skimmers.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://techcrunch.com/')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Clean sans-serif system throughout — headlines set bold and notably larger than body copy for immediate scan-priority, body text in a smaller, high-contrast gray-on-white for long-form readability. No serif accents; typography is utilitarian, optimized for fast scanning over editorial elegance.', 'High-contrast black/white base palette keeps the page feeling neutral and content-forward, with a single accent color (TechCrunch''s signature green/teal in the logo and interactive elements like CTA buttons and category tags) used sparingly so it reads as a signal, not decoration. Layout is a hero-plus-grid pattern: one dominant lead story up top, then a dense multi-column card grid of thumbnail+headline+byline units organized into topical rails (AI, Startups, Venture, Transportation, Security).', 'Size and position do the hierarchy work, not color: the hero headline is largest and top-left (natural reading start point), followed by descending card sizes as you move down/right. Thumbnails are uniformly cropped so the eye can pattern-match story-to-story quickly rather than getting snagged on inconsistent image shapes. Category badges act as small wayfinding anchors above each headline, letting readers filter mentally before they even read the title.', 'The density-first card grid: dozens of story units packed above the fold with minimal whitespace between them, prioritizing ''give me everything happening right now'' over breathing room — a deliberate trade of aesthetic minimalism for maximal scan-and-choose efficiency, unusual compared to slower, whitespace-heavy publications.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://techcrunch.com/')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), 'Kimi: Threat or menace?'), (( SELECT id FROM b), 'Databricks hits $188B valuation, extending its run as AI''s favorite second act'), (( SELECT id FROM b), 'Patreon stops asking AI bots not to scrape — and starts blocking them'), (( SELECT id FROM b), 'Vertu wants executives to pay $6,880 for an AI agent'), (( SELECT id FROM b), 'Why the first GPU financiers are turning to inference chips in a $400 million deal');

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('Wired', 'https://www.wired.com/', 'Global', false)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'Wired headlines mix two registers: (1) declarative-investigative statements that read like a verdict — subject + verb + concrete claim, no hedging (''Madison Square Garden Kept a List of Gay Celebrities'') — and (2) formula heads built on a noun-phrase + colon or ''The [Adjective] [Noun] of X'' template that signals a trend-piece (''The Uncanny Rise of the AI Model-Welfare Movement''). Service/how-to pieces use direct address with an implied command (''Here''s How to Stop It'', ''How to Protect Yourself From X''). Numbers and proper nouns (company names, tech terms) are front-loaded to establish stakes fast; adjectives are sparing but precise (''uncanny'', ''momentous'') rather than generic superlatives.', 'Leads open on a single, tightly observed scene or fact rather than throat-clearing context — a specific device, courtroom filing, chat log, or moment of confusion — then pull back within 2-3 sentences to state the larger stakes in plain declarative language. The nut graf typically arrives by paragraph 3-4 and names precisely what is new/contested, often with a pointed ''but'' or ''and yet'' pivot.', 'Inverted-pyramid meets narrative: news/investigative pieces front-load the core finding then layer in sourcing, documents, and pushback in descending order of importance; feature/trend pieces alternate between a running anecdotal throughline (a person, product, or company) and reported context blocks. Subheads chop long pieces into scannable 300-500 word chunks, each answering one implicit question. Pull quotes from sources appear roughly every 3-4 paragraphs to break up analysis.', 'Short paragraphs, often 2-4 sentences, with frequent one-sentence paragraphs used for emphasis or pivot. Sentence rhythm alternates long, subordinate-clause-laden explanatory sentences with a short punchy sentence that lands the point.', 'Confident, slightly skeptical insider tone — technically fluent without being academic, willing to editorialize in a dry, understated way rather than through hedging or exclamation. Treats readers as smart but time-pressed: explains jargon in-line with a quick apposition rather than a separate explainer paragraph. Not afraid of a wry or ominous closing line.', 'Bold-faced subheads every few hundred words; embedded pull quotes set in larger type; bulleted specs/numbered steps in service journalism; inline hyperlinks used as a scanning aid to signal ''related depth available here'' without breaking flow; sidebar boxes (''Related Stories'', ''Editor''s Picks'') and a persistent ''Save Story'' bookmark icon beside each headline.', 'Frequent use of the concrete, almost forensic detail (a specific line from a leaked document, a exact dollar figure, a timestamp) dropped into an otherwise analytical paragraph to re-anchor abstraction in evidence — this is Wired''s signature move for maintaining credibility while writing about speculative or techno-futurist topics.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://www.wired.com/')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Bold, oversized sans-serif headline type (a grotesque/condensed cut) set in near-black or pure black against white for maximum contrast, contrasted with a much smaller, often all-caps kicker/section label in Wired''s signature red above the headline. Body copy uses a clean serif or humanist sans at a generous line-height for long-form readability; bylines and timestamps run in small, muted gray caps.', 'Predominantly stark white background with black text, punctuated by Wired''s core brand accent — a saturated red/orange used sparingly for section tags, ''Save'' icons, dividing rules, and hover states — plus occasional gradient-heavy editorial illustration or photography that supplies color the UI itself withholds. Layout is a dense, magazine-style grid: a large hero image/headline block up top, then multi-column river of story cards mixing different image aspect ratios and headline sizes to signal hierarchy without needing much explanatory text.', 'Hierarchy is driven almost entirely by type size and image scale rather than color: the lead story gets a full-bleed image and the largest headline type, secondary stories shrink progressively, and low-priority links collapse to text-only rows in a sidebar ''river.'' Category/section kickers in red act as a consistent scanning anchor so the eye can jump from section to section even as headline size varies.', 'The signature red rectangular ''kicker'' tag sitting directly above/beside each headline (naming the vertical: BUSINESS, SECURITY, GEAR, CULTURE) — a small, consistent, high-contrast device that turns a dense homepage into an instantly scannable taxonomy and is arguably Wired''s most recognizable design signature across two decades of redesigns.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://www.wired.com/')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), 'Madison Square Garden Kept a List of Gay Celebrities'), (( SELECT id FROM b), 'The Uncanny Rise of the AI ''Model Welfare'' Movement'), (( SELECT id FROM b), 'Inside the Chip Factory That Could Decide the AI Race'), (( SELECT id FROM b), 'Your Car Is Spying on You. Here''s How to Stop It');

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('The Verge', 'https://www.theverge.com/', 'Global', false)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'Sentence case, not Title Case — a deliberate house-style signature. Headlines read as flat declarative statements (''Google is turning Search into an AI agent'') rather than clever wordplay; reviews use a colon structure: ''Product Name review: two-to-four word verdict'' (e.g. ''Samsung Galaxy Z Fold 7 review: thin is in''). Breaking news headlines front-load the company/product name as subject, verb second, so the news value reads left-to-right with no throat-clearing.', 'Leads with the concrete fact or scene, not a rhetorical question — first sentence typically states what happened/what it is, then second sentence pivots to why it matters or the writer''s take. Reviews often open with a one-line verdict-style hook before any spec dump. Breaking/live stories open mid-stream (''Update: ...'') assuming reader context rather than re-explaining from scratch.', 'Inverted-pyramid news lead followed by short contextual paragraphs; longer features and reviews break into bolded subheads (often short editorial commentary, not just topic labels) with embedded links to prior Verge coverage functioning as connective tissue/citations. Live/developing stories run as a StoryStream — a chronological feed of dated updates under one headline rather than one static article per development.', 'Short, 1-3 sentence paragraphs with generous white space; long sentences are rare — clauses are broken up for scanning rather than flowing prose.', 'Knowing, casual-smart, insider-voice — talks to readers like someone already fluent in tech culture, comfortable being blunt or lightly snarky about corporate spin, but not jokey for its own sake. Confident, opinionated verdicts stated plainly rather than hedged.', 'Bolded mid-article subheads, bulleted spec/pros-cons lists in reviews, pull-quotes for feature pieces, inline hyperlinks as de facto citations, ''Update:'' timestamp tags on developing stories, and numbered lists for roundup/best-of pieces.', 'Heavy internal hyperlinking — nearly every proper noun (company, product, past event) links to another Verge story, turning articles into a self-reinforcing web that keeps readers inside the site; combined with an affiliate/ethics disclosure line on reviews and frequent ''Update:'' timestamped amendments that keep older URLs alive and freshly indexed rather than publishing a new post per development.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://www.theverge.com/')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Custom bold, condensed display sans-serif for headlines and the wordmark (thick, almost tabloid-weight strokes) contrasted against a plain, high-legibility body sans for article text — a deliberate mismatch between maximalist display type and restrained reading type.', 'Mostly black-on-white canvas punctuated by loud, clashing accent colors (the Verge''s signature yellow/orange plus rotating brights) used only in small doses — topic ''eyebrow'' pill labels, rule lines, hover states — so color reads as a wayfinding system, not decoration. Layout is a dense, uneven river/grid of story cards (the ''StoryStream'' homepage) rather than a symmetric 3-column grid: one oversized lead card, then a scrappy mix of card sizes creating a magazine-cover, almost chaotic energy.', 'Size and boldness of headline type — not color — is the primary signal of story importance; the lead story gets a full-bleed image plus the largest type size, secondary stories shrink in both image and type in a clear but irregular step-down, and thick black divider rules chunk the page into sections so the eye can skip rather than scroll linearly.', 'The 2022 site redesign''s maximalist, intentionally ''unfinished-looking'' magazine layout — oversized condensed headline type, colorful pill/eyebrow category tags, and a deliberately irregular card grid — a stylistic outlier among tech sites that mostly go minimal/white; it reads more like a print magazine cover than a typical news feed.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://www.theverge.com/')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), 'Samsung Galaxy Z Fold 7 review: thin is in'), (( SELECT id FROM b), 'Google is turning Search into an AI agent'), (( SELECT id FROM b), 'Apple''s next iPhone might finally ditch the notch for good'), (( SELECT id FROM b), 'Update: the OpenAI and Apple lawsuit, explained');

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('Ars Technica', 'https://arstechnica.com/', 'Global', false)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'Colon-split two-part headlines: a punchy/wry clause, colon, then the substantive news clause (e.g., ''Rocket Report: SpaceX...''). Recurring franchise prefixes (''Rocket Report,'' ''Dying for dollars,'' ''Biz & IT'') act as section brands. Headlines favor concrete nouns/numbers over vague adjectives, and often smuggle in a light editorial verdict (''...and that''s a problem,'' ''...is a mess'').', 'Ledes open with a concrete, often slightly wry scene-setting or stakes-establishing sentence rather than a dry summary lede — frequently naming the company/agency/product and the consequence in sentence one, sometimes with a one-line editorializing aside before the nut graf explains why it matters.', 'Inverted-pyramid news structure with a distinct Ars twist: nut graf up top stating what happened and why it''s significant, followed by a technical-context section (how the tech/policy/science actually works, often several paragraphs deep) aimed at an informed-but-not-expert reader, then implications/reactions, and frequently a closing paragraph that zooms out to broader industry or historical context rather than a flat ending.', NULL, 'Technically literate, skeptical-of-hype, dry/deadpan wit deployed sparingly rather than constantly; treats readers as smart adults who want the actual mechanism explained, not dumbed down; unafraid of mild snark toward corporate PR-speak or vague official statements, quoting them to let the absurdity speak for itself.', NULL, 'Heavy use of embedded hyperlinks to primary sources (patents, court filings, papers, prior Ars coverage) as a trust/rigor signal, plus recurring themed franchises (Rocket Report roundups, Risk Assessment security column, Biz & IT) that give regular readers a predictable cadence; also frequent ''to be sure'' style caveat paragraphs that pre-empt reader pushback.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://arstechnica.com/')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Bold, high-contrast sans-serif headlines (historically a condensed/heavy grotesque) sized noticeably larger than deck/body text, creating a clear three-tier hierarchy: large headline, smaller gray/muted deck (dek) sentence beneath it, then small metadata line (byline, date, comment count). Body text uses a comfortable serif-adjacent or clean sans reading face with generous line-height for long technical articles.', 'Signature Ars orange/red accent color used sparingly for links, category tags, and hover states against a mostly white/light-gray (or dark-mode near-black) background — a restrained, editorial palette that keeps focus on text density rather than decorative color; layout is a dense, text-forward multi-column grid (more NYT-tech-desk than glossy magazine), prioritizing headline count over big imagery, reflecting its long-running low-clutter, ad-conscious design ethos.', 'Homepage leads with one dominant hero story (large image + oversized headline) at top-left/center, flanked by a dense river of secondary headline-only or headline+thumbnail river items below and a sidebar of ''most read''/latest listings; category labels (small caps or colored tags like ''BIZ & IT'', ''SCIENCE'', ''GAMING & CULTURE'') sit above headlines as scannable wayfinding before the eye ever reaches the headline text.', 'The comment count badge next to each headline (Ars has one of the web''s most engaged, long-running technical comment communities) functions as a visible social-proof/engagement signal baked directly into the headline list — a design element rarely seen on comparably dense at other outlets, signaling that the comments section is treated as part of the editorial product, not an afterthought.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://arstechnica.com/')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), 'Rocket Report: SpaceX''s Starship reaches new heights, Blue Origin''s New Glenn stumbles'), (( SELECT id FROM b), 'Risk Assessment: How a decades-old protocol keeps getting used to knock sites offline'), (( SELECT id FROM b), 'Biz & IT: Microsoft says AI agents need guardrails before they get more autonomy'), (( SELECT id FROM b), 'Dying for dollars: How a hospital''s ransomware payment decision plays out for patients');

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('Engadget', 'https://www.engadget.com/', 'Global', true)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'Short, declarative, subject-verb-object statements that state a fact or judgment rather than tease it (''Smart speakers could help OpenAI lose even more money'', ''OnePlus is officially leaving the US and Europe''). Company/product name almost always leads the headline. Occasional rhetorical question headlines used for opinion/culture pieces (''Are OLED TVs still worth the premium in 2026?'', ''What are your plans for AI Appreciation Day?''). Verbs carry judgment (''bans'', ''sues'', ''calls... rotten to its core'') rather than neutral reporting verbs — the headline itself telegraphs the outlet''s skeptical stance.', 'Leads with a specific, dated anecdote or named-source quote rather than a generic topic sentence — e.g. the OpenAI speaker piece opens with ''This past spring, former OpenAI executive Fidji Simo warned employees...'' quoting an internal phrase (''distracted by side quests'') that becomes the article''s organizing metaphor, immediately followed by a named Bloomberg reporter''s scoop as the news peg.', 'Inverted pyramid: news peg + skeptical framing first, then supporting market data, then an outside expert quote (named, titled — e.g. ''Jitesh Ubrani, the director of worldwide device trackers at market research firm IDC'') to substantiate the take, then historical precedent/comparison (Amazon Alexa, Meta Portal), closing with a qualified concession before reasserting the critical thesis. Minimal use of subheads, bullets, or bold within the body — it reads as continuous analytical prose, not a scannable listicle.', 'Longer paragraphs (150-250 words) that braid one direct quote into several sentences of the writer''s own analysis; sentences alternate between compound explanatory statements and short quoted fragments for texture.', 'Skeptical, dryly critical, and conversational — treats companies as characters with motives and failures rather than neutral entities. Not afraid of a light editorializing aside (the dek ''This feels like the epitome of a distracting side quest'' is opinion stated as plain fact). Technically fluent but jargon-free, accessible to a general reader.', 'On the homepage: colored category badges (AI, Apple, Gaming) sit above every headline; comment counts and relative timestamps (''15 min ago'') sit below. Within articles: almost no bullets/bold/subheads — the formatting work happens at the headline+dek+badge level before you ever click, not inside the body copy.', 'Headline-as-verdict: the dek functions as a one-line editorial thesis statement (not a summary), e.g. ''This feels like the epitome of a distracting side quest'' — readers get the writer''s opinion before the first paragraph even starts. Company internal jargon (''side quests'') is lifted and reused ironically as connective tissue through the piece.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://www.engadget.com/')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Large, bold sans-serif headlines (~20-24px) with high contrast against white background; secondary text (bylines, timestamps, deks) rendered smaller and in gray to create a clear two-tier reading order per card.', 'White background, dark gray body text, card-based grid. Category badges are the only saturated color note (blue for AI, red for News, purple for Gaming) and function as a color-coded wayfinding system across an otherwise restrained palette. Hyperlinks in muted teal/blue. Generous whitespace between blocks keeps a high story-density page from feeling cluttered.', 'Eye moves hero image with overlay headline (top, largest) to a three-across secondary carousel to a long single-column scrolling feed of thumbnail-left/text-right story rows. Each row is a self-contained stopping point — thumbnail anchors the eye, category badge signals topic before headline is even read, headline carries weight, gray metadata recedes.', 'Color-coded topic badges placed directly above every headline — a lightweight, consistent tagging system that lets readers triage the whole homepage by subject color before reading a single word, doing the job a section-nav menu would otherwise do.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://www.engadget.com/')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), 'Smart speakers could help OpenAI lose even more money'), (( SELECT id FROM b), 'OpenAI''s first device will reportedly be a ''humanlike'' rechargeable speaker'), (( SELECT id FROM b), 'Apple calls OpenAI''s hardware business ''rotten to its core'' in trade secret theft lawsuit'), (( SELECT id FROM b), 'Days after laying off 3,200, Xbox CEO Asha Sharma tapped to advise the Federal Reserve on jobs');

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('CNET', 'https://www.cnet.com/', 'Global', false)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'Utility-first, benefit-forward formula: [Actionable Verb] + [Specific Product/Topic] + [Concrete Benefit/Number/Deadline]. Heavy use of numerals (''7 Ways'', ''7 Best''), direct address (''Your''), and urgency words (''Before,'' ''Now,'' ''Today''). Deal/listicle heads follow ''The Best X for Y'' or ''X vs. Y: Which Should You Buy?'' Review heads follow ''[Product Name] Review: [One-line verdict]''. News heads are flat and factual: ''[Company] Announces/Launches/Confirms [Thing]''.', 'Leads with the single most concrete, practical stake for the reader in sentence one — often a direct answer or a surprising fact/number — rather than scene-setting. Reviews often open with a blunt verdict sentence (''The iPhone 16 is the best iPhone Apple has made in years, but...'') before any context. News stories open with the who/what/when in one tight sentence, then immediately pivot to ''why it matters to you.''', 'Inverted pyramid: verdict/answer up top, supporting detail and context after. Reviews and explainers use frequent H2/H3 subheads phrased as questions or short imperatives (''Should you buy it?'', ''Battery life'', ''What this means for you''). Listicles are numbered with bolded product/item names as mini-headlines. Most articles end with a short FAQ block or a ''bottom line'' takeaway paragraph rather than a narrative close.', 'Very short paragraphs, often 1-3 sentences, optimized for mobile scanning. Sentences are short and declarative with minimal subordinate clauses. Numbers, prices, and specs are kept as numerals (not spelled out) to aid scanning.', 'Plainspoken, consumer-advocate, second-person (''you''/''your''), mildly conversational but not jokey — reads like a knowledgeable friend giving you a straight answer, not a magazine essayist. Confident and declarative; hedges are minimal and specific (''in our testing'') rather than vague.', 'Bolded key terms and product names inline; bulleted spec/feature lists; numbered listicle formatting; pull-quote style callout boxes for ''key takeaway'' or ''CNET says''; embedded comparison tables for specs/pricing; sticky ''jump to'' table of contents on longer explainers; frequent inline hyperlinks to related coverage; star-rating badges on reviews.', 'Constant service-journalism framing: nearly every piece answers an implicit reader question (''should I buy this,'' ''how do I do this,'' ''is this a scam''). Products/specs are frequently rendered in short bolded fragments or bullet specs rather than prose, and star ratings/scorecards accompany reviews. Deal and pricing pieces are stamped with real-time price callouts and ''why we picked this'' one-liners under each item.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://www.cnet.com/')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Bold, tightly-tracked sans-serif headlines (a proprietary/customized grotesk) at heavy weight for hierarchy, paired with a lighter-weight sans for body and deck text. Headline sizes step down clearly across hero > secondary > card > list-item tiers, with consistent size/weight jumps rather than gradual scaling.', 'White/light-gray background with CNET''s signature orange-red as the primary accent (used for logo, category labels, CTA buttons, and ''Deal''/''Save $X'' badges), plus black text for maximum contrast/scanability. Layout is dense and grid-based — many story cards packed above the fold — reflecting a high-traffic aggregator design rather than a slow editorial magazine feel.', 'Classic ''hero + rail'' homepage layout: one dominant lead story with large image and oversized headline at top, flanked by a secondary column of smaller story cards; below that, horizontally-scrolling or grid-based topic modules (Reviews, Deals, How-To) each with their own mini-hero. Thumbnail images are used aggressively — nearly every headline is paired with an image or video-play icon, and video/deal badges overlay thumbnails to distinguish content types at a glance.', 'The orange price/deal badge system — small, high-contrast orange or red rectangular tags overlaid on thumbnails or inline with headlines (''Save $200'', ''4.5 stars'', ''Editors'' Choice'') that let readers scan commercial value and editorial verdict without reading any text, functioning as a visual shorthand unique to CNET''s hybrid news-plus-shopping identity.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://www.cnet.com/')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), 'Best iPhone to Buy in 2026'), (( SELECT id FROM b), 'This $200 Deal on the Sony WH-1000XM5 Won''t Last Long'), (( SELECT id FROM b), 'ChatGPT vs. Gemini: Which AI Chatbot Should You Use?'), (( SELECT id FROM b), 'Your Internet Bill Is About to Go Up. Here''s Why');

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('Business Insider', 'https://www.businessinsider.com/', 'Global', false)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'Numbered listicle (''7 signs you''re...''), first-person insider testimony (''I did X, here''s what happened''), or the ''named person + specific number + consequence'' formula (''A Goldman Sachs VP explains why he quit a $400,000 job''). Headlines almost always contain a concrete number, dollar figure, job title, or company name rather than an abstract claim — specificity is the engine of the click.', 'Leads with a single vivid, concrete anecdote or quote from one named person before zooming out to the trend or data — ''When [Name] got the email telling her she''d been laid off, she was on a beach in Portugal.'' The nut graph (the ''why this matters'' paragraph) typically arrives by paragraph 2-3, tagged with a bolded summary line at the very top of the piece (''Here''s what you need to know'' style bullet recap).', 'Inverted-pyramid meets magazine feature: bolded 3-bullet TL;DR block at top, then short narrative lead, then a subhead-broken march through supporting data points, quotes from 2-4 sourced experts/executives, and often a numbered or lettered list structure even inside non-listicle pieces. Ends abruptly on a forward-looking quote or data point rather than a summarizing conclusion.', NULL, 'Breezy, plain-spoken business-casual — avoids jargon or immediately defines it, uses contractions and second person (''you''), injects light skepticism or wit toward corporate-speak and executives, but stays fact-forward rather than snarky. Confident, direct, slightly conspiratorial (''insider'' framing implies access others don''t have).', NULL, 'Heavy reliance on named, quantified ''proof'' — the article''s authority comes from a named source with a title and company, plus a specific dollar figure, percentage, or year, embedded within the first 100 words. Also uses frequent bolded subheads phrased as mini-headlines that let scanners get the whole story without reading body text, and inline hyperlinked context bridges (''as BI previously reported'') that stitch pieces into a larger ongoing story.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://www.businessinsider.com/')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Bold, tightly-tracked sans-serif (a custom/Helvetica-adjacent grotesque) for headlines set large and black, with a clear three-tier hierarchy: oversized lead headline, mid-size deck/subhead in a lighter or gray weight, and small all-caps or condensed kicker labels (section tags like ''TECH'', ''MARKETS'', ''STRATEGY'') sitting above headlines in colored text.', 'Predominantly white background with black text for maximum scan contrast, punctuated by a single accent color (BI''s signature red/orange) used sparingly for section kickers, ''Subscribe''/paywall CTAs, and hover states. Homepage layout is a dense, modular grid — a dominant hero story with large image up top, flanking secondary story rails with thumbnail-plus-headline pairs, and horizontally-scrolling ''trending''/topic carousels lower down.', 'Image size and headline font size do the hierarchy work rather than color — the single biggest photo plus largest type marks the lead story, and hierarchy steps down through 2-3 visibly distinct type sizes as you scan down and across columns, letting readers triage importance at a glance without reading decks.', 'The small colored all-caps section kicker/eyebrow label (e.g., a red ''MARKETS'' or ''TECH'' tag) sitting directly above every headline — a consistent micro-label system that lets a reader categorize hundreds of homepage items at a glance without any of them needing a full description.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://www.businessinsider.com/')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), 'I retired at 35 with $3 million — here''s exactly how I did it'), (( SELECT id FROM b), 'A Goldman Sachs managing director explains why he''s betting big on AI startups'), (( SELECT id FROM b), '7 signs your boss is quietly preparing to fire you'), (( SELECT id FROM b), 'Meet the 29-year-old who turned a side hustle into a $50 million business');

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('HuffPost', 'https://www.huffpost.com/', 'Global', true)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'Short punchy declarative statements built around a strong verb or a shocking juxtaposition, often front-loaded with a single-quote ''zinger'' quote as the hook: ''Bats*** Crazy'': Critics Issue Stark Warning After Trump''s Bizarre Election Speech. Two-part structure is common — [Colorful quote or label in single quotes]: [Rest of headline as declarative sentence]. Also frequent is the ''X Mocked/Slammed/Roasted For Y'' formula (MAGA Lawmaker Mocked For ''Embarrassingly Idiotic'' Meltdown Over Canada) and first-person confessional titles for personal essays (I Lost My Job Because I Wouldn''t Let My Employer Hit My Toddler). Numbers and hard facts anchor news headlines (Taylor Farms Recalls Lettuce In 27 States Amid Cyclospora Outbreak).', 'News headlines open with the most damning or absurd detail up front rather than burying the lede — the emotional reaction (Outrage, Mocked, Critics Appalled) or the quote itself does the work of a hook before the reader even clicks. Personal-essay headlines use a two-sentence cliffhanger structure: a flat factual first sentence, then a second sentence that promises a twist (I Was Married To One Of The World''s Biggest Stars For Over 3 Decades. Here''s What I Discovered After I Left.)', 'Cards on the homepage are organized into tiered modules (Trending, Latest News, What''s Happening, topic verticals) rather than one long river, so skimming happens at the module level first, then the headline level. Individual articles favor short, single-idea paragraphs (rarely more than 2-3 sentences) built for mobile scroll, with quotes from tweets/social posts embedded as evidence rather than paraphrased.', 'Very short — one to three sentences per paragraph, heavy white space, frequent single-sentence paragraphs for emphasis, built explicitly for scanning on a phone screen rather than sustained reading.', 'Wry, indignant, and unapologetically opinionated on politics/culture coverage — mockery and outrage are treated as newsworthy reactions in their own right (note how many headlines center on being ''mocked,'' ''roasted,'' or eliciting ''outrage''). Personal essays shift to a warm, confessional, first-person register. Sports and straight-news items stay comparatively neutral and factual.', 'Bold/quoted phrases lifted into headlines and subheads; embedded social media posts (tweets) used as primary source material within the body; large lead photography above the fold on every story; related-story links interspersed in text; section/topic tags above headlines to aid scanning.', 'Weaponized scare-quotes: pulling a vivid, damning phrase directly from a source or critic and using it verbatim as the headline''s hook (e.g., ''Beyond Disgusting'', ''Embarrassingly Idiotic'', ''Bats*** Crazy'') so the outrage feels sourced rather than editorialized, while still delivering a strong emotional charge.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://www.huffpost.com/')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Bold, high-contrast sans-serif headlines (heavier weight than body text) sitting directly under or beside thumbnail images; headline type is the dominant visual element on cards since decks/bylines are minimized or hidden until click-through, forcing the headline to carry all the persuasive weight.', 'Restrained neutral palette — white/light gray background, black text — so that photography (not chrome or brand color) provides all the visual energy and differentiation between stories; layout is a dense, grid-like stack of image+headline cards typical of high-traffic aggregator sites, optimized for maximum scannable links per screen rather than editorial whitespace.', 'Tiered card modules (Trending at top, then Latest News, then What''s Happening, then topic verticals) create a clear scan path top-to-bottom; within each module, image size signals importance — hero/trending items get larger thumbnails (up to ~434x244px) while lower-priority items shrink to ~200x200px, so size alone communicates editorial weight without needing extra design elements.', 'The image-forward card grid where every single story, regardless of topic, is represented identically as a photo-plus-bold-headline unit with almost no supporting text (no visible deck/subhead, minimal byline) — the homepage functions like a headline-and-photo index rather than a magazine cover, maximizing the number of clickable entry points per scroll.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://www.huffpost.com/')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), '''Bats*** Crazy'': Critics Issue Stark Warning After Trump''s Bizarre Election Speech'), (( SELECT id FROM b), 'MAGA Lawmaker Mocked For ''Embarrassingly Idiotic'' Meltdown Over Canada'), (( SELECT id FROM b), 'I Was Married To One Of The World''s Biggest Stars For Over 3 Decades. Here''s What I Discovered After I Left.'), (( SELECT id FROM b), 'Taylor Farms Recalls Lettuce In 27 States Amid Cyclospora Outbreak');

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('Toss Tech (토스 기술 블로그)', 'https://toss.tech/', 'Korea', true)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'Colon-split two-part titles: a punchy metaphor/hook clause, then a colon, then the literal subject — e.g. ''토스팀이 AI 파도를 마주하는 방법: AI Surf Day'' (How the Toss team meets the AI wave: AI Surf Day). Also common: a first-person or team-voiced ''why'' framing that states a surprising choice, e.g. ''디자이너가 시안 대신 앱을 만든 이유'' (Why designers build apps instead of mockups), and blunt self-critical questions used as titles, e.g. ''우리 팀의 문서화는 왜 실패할까?'' (Why does our team''s documentation fail?). Headlines favor a concrete internal artifact/program name (AI Surf Day, es-toolkit) over abstract topic labels.', 'Opens with a relatable, slightly anxious observation about a shared industry moment (e.g., the disorienting speed of AI change) rather than a thesis statement — puts the reader''s own uncertainty on the page first, then pivots to ''here is how our team responded,'' making the org''s initiative feel like an answer to a feeling the reader already has, not a press release.', 'Named-program explainer structure: cultural/emotional framing intro -> ''What is X?'' subhead defining the initiative -> ''Program components'' subhead breaking it into named sub-tracks (each getting its own emoji-tagged subheading) -> individual case studies per contributor, each with role + concrete initiative + outcome, often in bullet or table-like form -> closing reflection that returns to the opening metaphor.', 'Short-to-medium paragraphs, rhythm deliberately varied: narrative/reflective passages run longer, but any time the piece explains a mechanism or lists a program''s parts it drops into tight 2-3 sentence blocks or bullets — reads as scannable even in the discursive sections.', 'Conversational-professional ''we'' voice — first-person plural, not first-person singular; acknowledges uncertainty explicitly (''정답이 없기에'' — because there''s no single right answer) instead of projecting false authority; warm but not jokey, written like an internal team retro shared publicly.', 'Emoji embedded directly inside subheadings to tag each sub-program (🏄🏻‍♀️, 🏄🏻, 🏄🏻‍♂️) functioning as visual category chips; named case-study blocks (person + role + what they built) formatted like mini-profiles; italicized pull-quotes from practitioners; strategic bolding of key terms/outcomes rather than whole sentences; numbered lists for concrete missions/steps.', 'Borrows an external quote/metaphor (e.g., Jon Kabat-Zinn''s ''you can''t stop the waves, but you can learn to surf'') and threads it through the whole piece — the metaphor becomes the naming scheme for the entire program (Surf Day, Surf Club, Surf Weekly, Surf Evangelist), so the headline device and the org-chart device are the same device.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://toss.tech/')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Clean, neutral sans-serif for both headlines and body — no serif contrast, no display/script accents; hierarchy is built mostly through size and weight steps (large bold headline, medium-weight subhead, regular-weight body) rather than font-family switching.', 'White background with dark near-black body text and a single blue brand accent (from the Toss logo/nav) used sparingly for interactive elements and category tags; illustrations and inline emoji graphics carry muted pastel colors, giving color pops against an otherwise monochrome text field. Layout is a horizontally scrollable carousel of featured cards up top, transitioning into a standard vertical grid of article cards below.', 'Eye is guided top-down: nav bar (logo + category filters + search/subscribe) -> hero/featured carousel with large thumbnail-led cards -> grid of smaller uniform cards each with thumbnail, category tag, author, and one-line description. Category tags act as scannable color/label anchors that let readers filter by topic (Engineering/Design/Product) before committing to a headline.', 'The emoji-as-subheading-icon system carried from card thumbnails into the article body itself (e.g., surfing emoji tagging each sub-section of a themed program) — a small illustration/emoji vocabulary that runs consistently from homepage card to in-article structure, turning a corporate engineering blog into something that reads visually playful without sacrificing the minimal, professional card-grid layout underneath.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://toss.tech/')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), '토스팀이 AI 파도를 마주하는 방법: AI Surf Day'), (( SELECT id FROM b), '디자이너가 시안 대신 앱을 만든 이유'), (( SELECT id FROM b), '우리 팀의 문서화는 왜 실패할까?'), (( SELECT id FROM b), '얼굴 인식의 역사와 페이스페이의 미래');

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('우아한형제들 기술블로그 (Woowahan Brothers Tech Blog)', 'https://techblog.woowahan.com/', 'Korea', true)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'Two dominant patterns: (1) a plain-language problem/solution noun phrase naming the system and the pain point — ''멀티 어카운트 NACL 차단 자동화 도구 운영 및 개선 경험'' (operating and improving a multi-account NACL-blocking automation tool); (2) a confessional, almost diary-like first-person sentence that reads like something a colleague would say out loud — ''AI가 내 프롬프트를 흘려듣는 이유'' (why AI tunes out my prompts), ''한 번 성공하니 다음도 쉬울 줄 알았다'' (I thought success once meant it''d be easy again), ''사람도 AI도 놓친 번역 누락, ESLint 플러그인을 만들어 해결하기'' (a translation gap that both humans and AI missed — so I built an ESLint plugin to fix it). No clickbait numbers-listicle style; titles read as honest one-line summaries of a lesson learned, often naming the specific tool/technology built.', 'Articles open with a flat, relatable problem statement rather than a scene-setter or stat — e.g. ''보안팀의 중요한 일 중 하나는 공격 IP를 지금 당장 막는 일 입니다'' (one of security''s core jobs is blocking attack IPs right now). The hook is the mundane reality of the job, then a quick contrast (single-account simplicity vs. their actual dozens-of-accounts mess) that justifies why the post exists.', 'Chronological problem-solving arc labeled with hex-style section numbers (0x00, 0x01, 0x02...) instead of normal H2/H3 numbering — a small signature nerd-flourish. Typical arc: problem intro -> initial architecture (with diagram) -> feature/iteration additions -> a numbered list of concrete operational pitfalls hit in production -> before/after comparison table -> refined design principle -> reflective conclusion. Ends on a one-line takeaway/moral, not a generic summary.', 'Short paragraphs, frequent line breaks; sentence length varies deliberately — clipped declarative fragments used for emphasis (''이걸 자동화한 것이'') interleaved with longer subordinate-clause sentences unpacking a distributed-systems nuance. Verbatim example: ''단위 동작은 정상이고, 로그에는 200이 찍히고, 슬랙에는 GOOD이 떠 있는데, 실제 상태는 그와 조금씩 어긋나 있는 것'' — a rhythmic three-beat list building to the real point.', 'First-person plural, practitioner-to-practitioner voice (''우리는'', ''우리도'') — collegial and unguarded, admits failures and near-misses openly (Slack failure screenshots included) rather than presenting only the polished win. Technical precision coexists with plain conversational asides.', 'Numbered hex headers (0x00-0x06); architecture/flow diagrams (6 in the sample article); before/after code block comparisons; a metrics comparison table (pre vs post); inline code in backticks for function/technical terms; italicized figure captions; Slack screenshot inserts as evidence of real incidents; author bio card with photo at the end.', 'Aphoristic closing lines that compress the whole lesson into one quotable sentence, e.g. ''자동화가 똑똑해지는 것보다, 자동화가 정직해지는 것이 운영자에게는 더 큰 안도였습니다'' (an automation being honest brought more relief to the operator than an automation being smart) — the post builds toward a single memorable maxim rather than a bullet-list recap.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://techblog.woowahan.com/')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Clean, minimal sans-serif system typeface prioritizing Korean-text readability; heading hierarchy is understated — the standout typographic quirk is using hexadecimal section labels (0x00, 0x01...) inside article bodies instead of conventional heading numerals, giving a subtle ''written by/for engineers'' signal. Code blocks in monospace with preserved formatting (no heavy syntax-color theming noted).', 'Restrained, low-chroma palette — mostly white/neutral background with dark text, no loud brand color blocking; visual weight comes from content density, not decoration. Card-grid layout on the homepage: each entry pairs a thumbnail/author avatar with date, author name, headline, and short excerpt.', 'A dense horizontal top nav (25+ category links: AI, Backend, Frontend, AWS, Infra, Data, Security, Design, QA, GenAI, plus company programs like 우아콘/우아한테크세미나) does the heavy lifting for wayfinding, letting the body grid stay simple — newest-first reverse-chronological article cards, each scannable via date + author thumbnail + bold headline + 1-2 line excerpt, no rotating hero banner competing for attention.', 'The hex-numbered section headers (0x00, 0x01, 0x02...) inside long-form posts — a small but memorable typographic tic that signals engineering-culture authenticity, reinforced by embedding raw evidence (Slack alert screenshots of real production failures, before/after code diffs, comparison tables) directly in the flow rather than sanitizing failures out of the narrative.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://techblog.woowahan.com/')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), '멀티 어카운트 NACL 차단 자동화 도구 운영 및 개선 경험'), (( SELECT id FROM b), 'AI가 내 프롬프트를 흘려듣는 이유'), (( SELECT id FROM b), '한 번 성공하니 다음도 쉬울 줄 알았다'), (( SELECT id FROM b), '사람도 AI도 놓친 번역 누락, ESLint 플러그인을 만들어 해결하기');

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('카카오 기술 블로그 (Kakao Tech Blog)', 'https://tech.kakao.com/', 'Korea', true)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'Titles are built as a [Method/Tool]로 [specific task] 하기 construction — a gerund ''-하기'' ending that reads as ''here is how we did X,'' not clickbait. Example: ''AI 에이전트로 카카오톡 추천 지표 분석 자동화하기'' = Method + Object + Verb. Series posts are explicitly numbered in parentheses (''...개발자인가(3)'') rather than hidden — Kakao openly runs multi-part deep dives, and each installment restates the core question instead of just tagging ''Part 3''. A second pattern is the rhetorical-question headline aimed at an internal industry debate (''...개발자인가?'') that stakes a position readers will want to argue with. Headlines name real internal systems/teams, never generic listicle bait (''5 things about X'').', 'No shock-stat or personal-anecdote cold open. House style opens with a scoping statement — which team/problem this covers and why it mattered operationally — followed within the first two paragraphs by an explicit signpost sentence (''이 글에서는 ~에 대해 다룹니다'', roughly ''this post covers...''). The hook is credibility and concreteness: naming the actual internal system/pipeline by name so the reader knows ''this shipped inside Kakao,'' not a hypothetical.', 'Long technical narrative arc: context/motivation → problem definition → options considered → chosen approach with implementation detail (code, diagrams, config) → results/metrics → retrospective/lessons-learned close. Sections carry literal descriptive Korean H2/H3 headers stating exactly what''s inside (''배경'', ''문제 정의'', ''해결 방법'', ''결과'', ''마무리'') rather than clever/cute headers — scannability over cleverness. Author bio and role appear at top (name.name convention, e.g. ''rupert.kim'') plus category tag (''blog'') and exact publish date, reinforcing this is an internal-practitioner account, not marketing copy.', 'Short paragraphs (2-4 sentences), frequently broken further by numbered or bulleted sub-steps; long procedural explanations are chunked under sub-headers rather than run as continuous prose. Sentences favor concrete nouns (tool names, metric names, team names) over abstract claims.', 'Formal-polite ''-습니다/-합니다'' register throughout, first-person-plural or team-voice (''저희 팀은''), matter-of-fact and unhyped even when describing hard wins — confidence is shown via specificity (numbers, tool names, before/after) rather than adjectives. Self-aware and occasionally self-critical in retrospective sections (''한계점'', ''아쉬운 점'' — limitations, regrets) which is a deliberate credibility device distinct from Western corporate-blog triumphalism.', 'Card-based homepage listing (thumbnail + headline + author + date + category tag) trains readers to scan visually before committing to a post. Within articles the known house pattern uses: bolded key terms, numbered step lists for procedures, code blocks for implementation, diagrams/architecture images, and a closing references/link-out section — all devices oriented at letting an engineer skim to the relevant section rather than read linearly.', 'Explicit problem-to-solution transparency: rather than only presenting the polished final architecture, posts narrate the road not taken (alternatives tried and rejected) and end with a candid limitations section — a ''show the seams'' technique that builds trust with a peer-engineer audience more than a purely triumphant narrative would.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://tech.kakao.com/')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Clean sans-serif Korean/Latin system typeface prioritizing legibility over personality — headline weight is distinctly heavier/larger than the metadata line (author · date · category tag) beneath it, creating a clear two-tier hierarchy on every card: title first, provenance second.', 'Minimal palette anchored by a single blue accent against white/neutral background — color is used sparingly as a functional signal (links, tags, CTA) rather than decoratively, keeping the page content-first. Cards are arranged in a horizontal, evenly-gridded row rather than an asymmetric magazine layout, favoring predictability and fast scanning over editorial flair.', 'Homepage leads with a hero/tagline zone, then six labeled thematic pillars (Knowledge Sharing, Value Creation, Openness, Tech Ecosystem, Tech Library, Developer Recruitment) that frame the blog as an organizational program rather than just a feed, then a horizontal card grid of recent posts (uniform 370x208px thumbnails) each pairing image + title + author + date + category tag, ending in a dense sitemap-style footer linking to Kakao Developers, KakaoMaps API, GitHub/opensource, and conference sites (if kakao AI, Kakao Tech Meet) — the footer alone signals this blog sits inside a much larger developer-relations ecosystem.', 'The six-pillar thematic framing on the homepage (Knowledge Sharing / Value Creation / Openness / Tech Ecosystem / Tech Library / Developer Recruitment) — most corporate tech blogs just show a post feed, but Kakao frames the entire blog as a structured program with named pillars before you ever reach an article, doubling as both an editorial taxonomy and an implicit recruiting pitch.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://tech.kakao.com/')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), '개발을 넘어 AI로 사회문제를 해결하다'), (( SELECT id FROM b), 'AI 에이전트로 카카오톡 추천 지표 분석 자동화하기'), (( SELECT id FROM b), 'Vibe Coding하는 비개발자는 개발자인가(3)');

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('요즘IT (Yozm IT, Wishket Magazine)', 'https://yozm.wishket.com/magazine/', 'Korea', true)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'Two-part construction: a punchy quoted hook or rhetorical exclamation in quotation marks (often a spoken-thought fragment like a reaction), followed by a colon-less descriptive tail stating the concrete topic/outcome. E.g. ''"이 정도면 직접 만들겠는데?" 바이브 코딩으로 유료 앱 대체하기'' — quote hooks curiosity, tail delivers the SEO-friendly payoff (what was built/replaced). Also common: numeric/personal-stakes framing (''1인 빌더... 9개 동시 운영한 방법'', ''AI와 200만 줄의 코드를 작성하며 깨달은 것들'') pairing a big number with a personal transformation/lesson angle.', 'Starts in first person with a small, relatable frustration or moment of dissatisfaction (e.g., a paid app that seemed fine but slowly annoyed the author because it treated all check-ins equally) — grounding an abstract tech topic in a concrete personal anecdote before broadening to the larger trend (AI lowering the barrier to building your own tools).', 'Personal-anecdote lead -> problem statement -> named H2 sections that read like a mini case study (''핵심 기능 개발하기'', ''가장 큰 난관이었던 데이터 마이그레이션'', ''직접 유료 앱을 대체하고 얻은 결론'') -> reflective/philosophical closing rather than a tidy summary or CTA. Essentially: hook, build, struggle, lesson.', NULL, 'Conversational-reflective, first-person, thinking-out-loud; avoids heavy jargon even on technical topics; occasional self-aware humor about developer pain points; uses rhetorical questions to mirror the reader''s likely internal reaction, creating a sense of shared discovery rather than lecturing.', NULL, 'Frames technical/product content as a personal build-log/diary rather than a tutorial or news piece — bold is used sparingly to flag the single ''aha'' takeaway sentence per section (e.g. ''내가 납득하는 하루의 기준을 직접 만들었다는 느낌''), functioning like a pull-quote embedded inline instead of a separate callout box; screenshots are dropped in only after the concept is already explained in prose, so images confirm rather than carry the argument.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://yozm.wishket.com/magazine/')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Clear size-based hierarchy: large bold serif/sans title at top, smaller byline+date+read-time metadata line directly under it in gray, bold medium-size section headers (H2-equivalent) breaking the body into 3-4 named chapters, and slightly smaller bold subheads within sections. Body text uses generous line-height and whitespace; bold (not italics, not color) is the sole in-body emphasis device, reserved for key phrases and conclusions rather than random emphasis.', 'Light, neutral background with grayscale-dominant supporting text (metadata, timestamps, read time in gray) and colored category badges (e.g. [개발], [AI], [디자인], [프로덕트]) used as the main accent-color hits amid an otherwise restrained palette. Homepage layout is a hybrid grid: large featured/collection cards with big thumbnail images up top, transitioning into a denser list-style feed of headline+thumbnail+metadata rows further down.', 'Eye is directed by size-first cascade (title > section head > subhead > body) reinforced by whitespace gaps between sections rather than rules/dividers; thumbnails and mid-article screenshots act as visual anchors placed right after a concept is explained (not before), so images confirm the text rather than lead it; engagement metadata (views, comments, read time) sits small and quiet under headlines, never competing with the headline itself.', 'The consistent color-coded category bracket tag (e.g. "[개발]", "[AI]") prefixed directly onto/near every headline — a compact taxonomy device that lets readers scan the whole feed and sort by topic at a glance without reading each title.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://yozm.wishket.com/magazine/')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), '"이 정도면 직접 만들겠는데?" 바이브 코딩으로 유료 앱 대체하기'), (( SELECT id FROM b), '구글이 공개한 AI 에이전트 제작 노하우를 가져다 쓰는 법'), (( SELECT id FROM b), '1인 빌더, 클로드 코드로 프로젝트 9개 동시 운영한 방법'), (( SELECT id FROM b), '나만의 세컨 브레인: 옵시디언 기반 LLM 위키 구축기');

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('LINE Engineering (engineering.linecorp.com/ko)', 'https://engineering.linecorp.com/ko/', 'Global', true)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'No clickbait, no numbers-driven listicle framing. Titles are literal descriptions of what was built or fixed, usually in one of three shapes: (1) Problem→Action, e.g. ''HiveQL을 Spark SQL로 이전 시 발생하는 문제 해결하기'' (Solving the problems that occur when migrating HiveQL to Spark SQL); (2) Why-we-did-X, e.g. ''전통적인 CMS에서 LandPress Content로 CMS를 옮기는 이유'' (Why we moved from a traditional CMS to LandPress Content); (3) Flat noun-phrase capability description, e.g. ''독립적이고 범용적인 올인원 메시징 플랫폼'' (An independent, general-purpose all-in-one messaging platform), ''쿠버네티스를 활용한 선언형 클라우드 DB 서비스'' (A declarative cloud DB service built on Kubernetes). Titles almost always name the specific technology stack (Spark SQL, Ceph, ELK, Grafana, Swift Concurrency, Kubernetes) rather than a vague benefit, so readers self-select by tech stack, not by curiosity gap.', 'No narrative or anecdotal hook. Articles open with a section literally titled ''들어가며'' (Introduction/Getting started) where the author identifies their role/team first-person (''저는 데이터 엔지니어로...'') and states the concrete business/technical context that motivated the work — essentially a scoped problem statement, not a story. The hook is credibility + specificity, not suspense.', 'Rigid, almost templated engineering-report structure: 들어가며 (Intro/context) → 작업 배경과 대상 및 환경 (background, scope, environment) → a terminology/definitions subsection before any deep dive (e.g. ''트러블 슈팅 사례 소개 전 관련 용어 설명'') → the core content broken into discrete numbered ''phenomena'' or cases, each following an identical sub-pattern: situation → how to reproduce → root cause → solution/response strategies → references → 마치며 (closing) that summarizes quantified results, states what was learned, and names future work. This case-by-case template lets skimmers jump to the one failure mode relevant to them.', 'Short-to-medium: 3-5 sentences typical, expanding to 6-8 only for dense technical explanation. One idea per paragraph. Sentences are declarative and sequential (cause then effect), avoiding rhetorical questions or fragments.', 'Formal-but-collegial 존댓말, consistently first-person-plural ''저희''/''저희 팀'' — frames the work as a team accomplishment, not an individual flex. No humor, no hype adjectives; confident but understated (''~했습니다'' declarative statements). Closing lines are notably humble/grateful rather than promotional, e.g. explicitly thanking the reader for reading a long post.', 'Heavy use of H2/H3 headings that double as a table of contents/scan path; SQL/code blocks with inline comments (e.g. ''-- Hive'', ''-- Spark'') to show before/after behavior; comparison tables (Hive vs Spark behavior for the same function); bullet lists for enumerating alternatives or options; sparing bold, reserved for critical config keys (e.g. `spark.sql.hive.convertMetastoreOrc`) rather than general emphasis; diagrams/timeline images for system behavior; external reference links (often to Apache/GitHub source) supporting technical claims instead of citing them inline.', 'The ''define terms before using them'' subsection placed deliberately before the technical narrative begins, plus a strict per-case micro-template (situation → repro → root cause → fix → references) repeated identically across every problem in the post — this consistency is what makes long, dense troubleshooting posts skimmable, and it doubles as a reusable internal postmortem/runbook format.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://engineering.linecorp.com/ko/')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Standard sans-serif corporate typeface, dark text on light/white background for maximum long-form readability; heading hierarchy (H2 for major sections, H3 for sub-cases) is used strictly as a navigational skeleton rather than for decorative size jumps — headings read like a spec document''s section numbers, not headline typography.', 'Restrained, low-saturation corporate palette — neutral background, dark body text, minimal accent color use (mainly for links/CTA button). Header carries a multi-language switcher (Korean/English/Japanese/Traditional Chinese/Vietnamese) signaling the blog''s role as a global-facing engineering-brand property, plus a persistent ''careers'' CTA button tying the content marketing directly to recruiting. Social icons (Twitter/X, YouTube, Facebook, GitHub) sit near the header/footer.', 'List-based homepage: each post is a horizontal row/card with a thumbnail (~200-300px) + title + date + author/team attribution, stacked vertically in reverse-chronological order — hierarchy is driven by recency and thumbnail presence rather than large hero imagery or size-varied grid tiles. Within articles, hierarchy is carried almost entirely by heading depth and code-block framing rather than color or font-weight tricks.', 'The recurring inline Hive-vs-Spark SQL comparison blocks with paired comment-annotated code snippets — the design choice to show two near-identical code blocks side by side/sequentially (one labeled ''-- Hive'', one ''-- Spark'') so the reader can spot the behavioral diff themselves, rather than relying on prose description alone. This code-as-evidence pattern, combined with the terminology-first subsection, is the site''s most learnable, transferable device for technical writing.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://engineering.linecorp.com/ko/')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), 'HiveQL을 Spark SQL로 이전 시 발생하는 문제 해결하기'), (( SELECT id FROM b), '독립적이고 범용적인 올인원 메시징 플랫폼'), (( SELECT id FROM b), '전통적인 CMS에서 LandPress Content로 CMS를 옮기는 이유'), (( SELECT id FROM b), '쿠버네티스를 활용한 선언형 클라우드 DB 서비스'), (( SELECT id FROM b), '더욱 견고해진 LINE의 오픈소스 관리: OpenChain 인증과 그 뒷이야기를 소개합니다');

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('네이버 D2 (Naver D2)', 'https://d2.naver.com/home', 'Korea', false)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'Titles are almost always noun-phrase + colon or possessive construction naming the specific system/team plus the technical problem, e.g. ''[서비스/시스템 이름]의 [문제] 해결기'' or ''[기술] 도입기/회고''. Verbs are nominalized (''~하기'', ''~한 이유'', ''~회고'') rather than imperative or question-form clickbait. No numbers-listicle titles, no emotional adjectives — the headline itself functions as an abstract, telling you the system and the angle (design, migration, postmortem) up front.', 'Openings are almost never anecdotal or emotional. A typical D2 post opens with 1-2 sentences of context-setting: what service/team this is, what scale of traffic or data is involved, and the concrete problem that triggered the work (an incident, a scaling wall, a maintenance pain point). The hook is credibility and scale (''국내 최대 규모의 트래픽을 처리하는 시스템에서...'') rather than curiosity-gap phrasing.', 'Long-form engineering narrative broken into numbered or heading-based sections that usually follow a problem -> investigation/AS-IS -> design options considered -> chosen solution/TO-BE -> results (numbers, latency/cost improvements) -> lessons-learned arc. Frequently uses explicit before/after framing (AS-IS/TO-BE) borrowed from enterprise process docs. Ends with a short reflective closing paragraph, sometimes acknowledging tradeoffs or open problems rather than declaring total victory.', 'Short-to-medium paragraphs (3-6 sentences) each anchored to one claim or one step, frequently interrupted by code blocks, config excerpts, or numbered figure/table references rather than long unbroken prose blocks.', 'Dry, first-person-plural, engineer-to-engineer. Confident but hedged with real numbers and caveats (''완벽한 해결책은 아니지만''). No marketing voice, minimal exclamation points, closer to an internal postmortem or conference-talk transcript than a blog. Assumes the reader already knows the domain vocabulary.', 'Numbered section headings, inline architecture diagrams with 그림/표 captions, embedded code snippets, bolded key terms on first use, and explicit AS-IS/TO-BE comparison tables or bullet pairs.', 'Heavy use of the AS-IS/TO-BE comparison frame and of concrete quantified results (percentages, ms, QPS, node counts) as evidence rather than adjectives — claims are backed by a specific number almost every time a change is described. Also common: architecture diagrams referenced inline, and code snippets or config excerpts embedded as primary evidence rather than illustration.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://d2.naver.com/home')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Clean sans-serif (Naver''s in-house/system sans stack), fairly small body text sized for long technical reading, generous line-height for Korean text blocks; headings step down in weight/size rather than color to mark hierarchy — deliberately restrained, closer to a documentation site than a magazine.', 'Mostly white/light-gray background with black-gray text; Naver''s brand green appears only sparingly as an accent (logo, occasional link/button) rather than as a dominant theme color — the palette is deliberately neutral so it doesn''t compete with the technical content and diagrams.', 'Card-grid homepage: each post is a thumbnail image + title + short one-line summary + tag/date, arranged in a uniform grid so no single story is visually dominant — hierarchy is set by grid position/freshness (newest top-left) rather than by size or color emphasis. Within articles, hierarchy comes from heading levels and inline figure/table numbering, not decorative color blocks.', 'The uniform, editorially-flat thumbnail card grid on the homepage — every post gets the same-size card regardless of topic or importance, which visually signals ''this is a technical archive/library, not a magazine chasing your click'' and mirrors the restrained, evidence-first writing style.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://d2.naver.com/home')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), '네이버 검색의 SRE 시스템: AS-IS와 TO-BE'), (( SELECT id FROM b), '대규모 트래픽을 견디는 캐시 아키텍처 설계기'), (( SELECT id FROM b), '오픈소스 라이브러리 회고: 우리는 왜 이 도구를 만들었나'), (( SELECT id FROM b), '실시간 이벤트 처리 파이프라인, 카프카로 다시 설계하기');

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('당근 테크 블로그 (Daangn Tech Blog)', 'https://medium.com/daangn', 'Korea', true)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'Two-part, colon-split titles: a plain-English abstraction/claim before the colon, a concrete mechanism or outcome after it. E.g. ''Standardizing User Activation: How We Built a Shared Data Layer at Karrot.'' Non-colon titles are simple declarative process statements: ''Our Journey to Using Host Network in Kubernetes Pods,'' ''Karrot''s Journey to CDC with MongoDB.'' Almost every title names either the company/product (''Karrot''s Journey...'', ''당근마켓 AI의...'') or a concrete technical noun (Kubernetes Pods, MongoDB, CDC, GenAI Platform) — never abstract or clickbait phrasing. ''Journey to X'' and ''How We Built X'' are recurring templates signaling a first-person engineering narrative rather than a tutorial.', 'Near-identical ritual opener across authors: a friendly self-introduction using an internal English nickname, team name, and one-sentence description of the team''s mandate/vision — e.g. ''Hi! I''m Ssup, from the SRE team''s Cluster group... We handle everything from Kubernetes cluster operations to...'' or ''Hello, I''m Pepper, a Data Analytics Engineer on the Data Team at Karrot. Our team''s vision is to make user-focused decisions through data every day.'' This is followed immediately by a one-line statement of what the post will cover and, often, a quantified teaser result up front (e.g. ''we were able to save thousands of IP addresses... and significantly improve Job Pod creation speed'') before the deep technical narrative begins.', 'Long-form, numbered-and-nested outline: Background/Problem -> Goals/Requirements -> multiple named ''Challenges We Solved'' or solution sections (often literally numbered ''1. Reliability... 2. Cost... 3. Productivity...'') -> Results (with before/after data or code) -> Use Cases -> Conclusion/Closing Thoughts. Every article ends on an explicit reflective closing section (''Conclusion'' / ''Closing Thoughts'') that steps back to state the broader lesson learned, not just a summary of steps.', 'Short paragraphs (2-4 sentences), heavy use of numbered lists and bolded key terms to break up technical explanation; SQL/code comparisons shown as literal before/after blocks rather than described in prose.', 'First-person, conversational-professional ''engineer explaining to another engineer'' voice; humble and process-transparent (shows candidates considered and rejected, not just the final answer, e.g. three FirstLast model candidates with one marked chosen). Uses personal team nicknames and ''we'' throughout — reads like an internal engineering postmortem/design-doc turned into a public post, not marketing copy.', 'Deeply nested numbered/lettered subheadings (up to 3 levels), bold text on key terms and metric names, inline code formatting for identifiers (e.g. `users_visited_app_activation_daily`), comparative before/after code blocks, embedded diagrams/dashboard screenshots and data tables placed adjacent to the section that introduces them, and a stated read-time estimate (e.g. ''14 min read'') at the top.', 'Trade-off enumeration as narrative scaffolding: problems are decomposed into 2-3 named criteria (Reliability / Cost / Productivity; Pros / Cons of Host Network) and each gets its own subsection walking through the options tried before landing on the final design — making the reasoning process, not just the result, the content.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://medium.com/daangn')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Standard Medium serif/sans typographic system: large bold sans-serif H1 article title, medium-weight sans-serif subheadings in a clear size hierarchy (H1 title > H2 major sections > H3/H4 numbered subsections), body text in Medium''s standard readable serif/sans body font with generous line-height. Inline code and identifiers set in monospace to visually separate technical tokens from prose.', 'Minimal black-on-white Medium theme with a single-column, centered reading column (narrow measure ~680px) — no custom brand color scheme layered on top of Medium''s default. The publication''s own visual identity is confined to a circular carrot-badge logo and a horizontal top nav (Engineering / AI-ML / Data / Search / English / All / About) used for topic filtering rather than color styling.', 'Hierarchy is carried almost entirely by text weight/size and whitespace rather than color: bold numbered section headers create scan-points down the page, diagrams/tables/screenshots are inserted directly beneath the paragraph that introduces them (not floated aside), and bolded inline terms act as the eye''s resting points inside dense paragraphs so a skimmer can follow the argument''s spine without reading every sentence.', 'The recurring author self-introduction block at the very top of every post (nickname + team + one-line mandate) functions as a consistent ''masthead'' micro-pattern across a multi-author blog — it substitutes for a bio graphic and gives every otherwise-generic Medium template post the same recognizable Karrot-engineering voice before any design chrome kicks in.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://medium.com/daangn')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), 'Standardizing User Activation: How We Built a Shared Data Layer at Karrot'), (( SELECT id FROM b), 'Our Journey to Using Host Network in Kubernetes Pods'), (( SELECT id FROM b), 'Karrot''s Journey to CDC with MongoDB'), (( SELECT id FROM b), '당근의 GenAI 플랫폼');

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('뱅크샐러드 기술 블로그 (Banksalad Tech Blog)', 'https://blog.banksalad.com/', 'Korea', true)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'Two dominant molds. (1) Problem+method with a parenthetical technical footnote: ''[상황/목표]하는 법 (feat. [구체적 기술])'' — e.g. ''데이터 정합성을 유지하는 법 (feat. 낙관적 락)''. The parenthetical ''feat.'' tag works like a music-credit gag, signaling ''here''s the specific tool we''re spotlighting'' while keeping the main clause plain-language and searchable. (2) A skeptical rhetorical question as the headline itself, mimicking spoken disbelief — ''이걸 진짜 만든다고요?'', ''접근성을 지원한다는 착각'', ''React랑 Lottie로 게임을 만든다고요?'' — the ''~다고요?'' ending is a colloquial Korean tic (repeating back what someone said, incredulous) that turns a dry topic into a conversational beat. Multi-part series are numbered with ''| n편. [subtopic]'' (BX/UX/기초공사/완공편/증축편) so a saga reads like show episodes, not documentation.', 'Opens with a personal, almost email-style self-introduction naming the author''s real team and role before any technical content: ''안녕하세요 금융쇼핑 PA 백엔드 개발자 배지원입니다.'' This immediately breaks the anonymous-corporate-blog convention — you know who is talking and what they own. The very next sentence pivots straight to business context (why the team is doing gamification at all) before touching a single technical term, so the reader has motive before mechanism.', 'Consistent six-beat arc: (1) personal hook + service/business context, (2) concrete problem scenario stated in plain numbers before any jargon (e.g., a specific point-collision example: 1,000 SAL vs 1,200 SAL), (3) survey of 2-3 candidate solutions compared side by side, (4) chosen solution with reasoning for why it fits this specific domain (not solutions in the abstract), (5) implementation detail with real code/diagrams and the operational gotchas encountered, (6) close with measured results plus a forward-looking caveat (''we designed it to keep converging / stay flexible'') rather than a triumphant wrap-up.', 'Short paragraphs, frequently single-sentence, interleaved with bullet lists for comparing options and code blocks (Go/SQL) for showing the actual fix rather than describing it. Sentences alternate between short declaratives that land like conclusions (''데이터 정합성은 결코 타협할 수 없는 기본 중의 기본입니다.'') and longer connective sentences that walk through cause-and-effect reasoning.', 'Professional-conversational, not corporate-formal: uses 안녕하세요 greetings, 우리/저희 팀 (we/our team) constantly instead of passive voice, admits real problems and constraints before selling the solution. Confident but not hype-y — results are stated as facts with numbers, not adjectives.', 'Numbered multi-part series (1편/2편/3편) with distinct subtitles per episode; bracketed emoji icons (💡🧐⚠️) as inline signposts; bullet-point comparison tables for evaluating alternatives (e.g., pessimistic vs optimistic vs distributed lock); embedded code blocks and architecture/flow diagrams; bold or backtick-highlighted key terms (e.g. `샐(SAL)`) so in-universe/product jargon is visually distinguished from generic technical terms.', 'Named-author signature + ''feat.'' framing device used as a recurring headline/subtitle convention across many posts, turning each article into something closer to a byline-credited engineering diary entry than an anonymous corporate explainer — this is reinforced by emoji callout markers (💡 tip, 🧐 consider, ⚠️ warning) used as informal margin notes to flag asides inside otherwise dense technical prose, letting readers scan for ''the important bit'' without reading every line.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://blog.banksalad.com/')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Dark near-black body text (#2A2B33) on white background for maximum readability; sans-serif throughout (no serif contrast anywhere), keeping the whole site feeling like a product UI rather than a publication — headlines are set larger and bolder but in the same typeface family as body copy, so hierarchy comes from size/weight, not font-pairing.', 'A restrained white base broken only by a small multi-hue accent set — teal #00CD80, cyan #00CDCD, blue #0099FF, magenta #F582C6 — applied sparingly (tags, icons, thumbnail illustration accents) rather than as full-bleed color blocks, so the palette reads playful/brand-forward without competing with reading. Grid-of-cards layout with generous whitespace and consistent padding; each card carries a uniform placeholder-style square illustration (200x200), a headline, and a small tag row (#해시태그 style) under it, echoing social-post tagging conventions instead of traditional editorial category labels.', 'Two flat top-level sections (Tech / Culture) act as the entire nav — no deep taxonomy — so the eye goes: logo/nav bar → section tabs → card grid, each card weighted equally (same-size thumbnail, headline, tag row, date). Chronological descending order does the sorting rather than editorial curation modules (no ''featured'' hero treatment), which reads as ''this is an engineering changelog, not a magazine.''', 'The hashtag-style tag row under every headline (e.g. #데이터정합성 #일해라김뱅샐) is the single most distinctive device — it borrows social-media tagging language into a corporate engineering blog, and one recurring tag (''#일해라김뱅샐'', a in-joke/mascot-style team tag) functions as a running gag/brand mascot thread across otherwise serious technical posts, softening the tone and building a sense of an ongoing internal culture readers get let in on.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://blog.banksalad.com/')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), '뱅크샐러드가 게임을 만들 때 데이터 정합성을 유지하는 법 (feat. 낙관적 락)'), (( SELECT id FROM b), '이걸 진짜 만든다고요? 세상에 없던 게임, 샐러드게임 | 1편. BX'), (( SELECT id FROM b), '우리가 테스트를 하는 이유. 근데 이제 Golang을 곁들인'), (( SELECT id FROM b), '접근성을 지원한다는 착각');

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('컬리 기술 블로그 (Kurly Tech Blog / helloworld.kurly.com)', 'https://helloworld.kurly.com/', 'Korea', true)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'Two-part construction with an em-dash or colon splitting a punchy, almost narrative hook from a technical subtitle that names the actual stack/method — e.g. ''두 번 갈아엎은 이야기 — LLM Wiki + RAG 혼합기'' or ''현관문에도 얼굴이 있다: 배송 완료 사진 기반 On-device 오배송 탐지 시스템.'' The front half is written like a personal-essay title (confession of failure, a surprising personification, a superlative number), the back half is a dry technical descriptor so a search-scanning engineer instantly knows the domain. Numbers are used as bait (''15개'', ''148,000번의 대화'', ''전사 1위'').', 'Articles open by naming a concrete, relatable pain point before any architecture talk — e.g. stating plainly that general-purpose LLMs don''t know the company''s internal vocabulary/domain, then personalizing the stakes (''내가 두 번이나 갈아엎었다''). The hook is a problem statement + admission of failure/iteration, not a thesis statement; it invites the reader into a war story rather than a spec sheet.', 'Chronological, staged narrative: Stage 1 → what broke → Stage 2 → what broke → Stage 3 → what finally worked, each stage given its own labeled subheading (e.g. ''색인 유지가 룰인 구조'' → ''의미 매칭으로 전환'' → ''요약 임베딩 + 본문 키워드 검색 분업''). Ends with a comparison table scoring the approaches on named metrics (token efficiency, recall, precision, identifier search), then a short reflective closing section that steps back to a principle-level takeaway rather than just summarizing. This ''iterate, fail, iterate again, then generalize the lesson'' arc is the house structure.', 'Short paragraphs broken by subheadings every few hundred words; heavy internal signposting via bold-faced key terms and inline code formatting for identifiers (model names, table/field names), numbered lists for enumerated problems, and at least one comparison table near the end to compress three long narrative stages into a scannable grid.', 'First-person, confessional-engineer tone — admits what didn''t work before explaining what did, uses casual connective phrasing (''~해봤다'', ''~라는 걸 깨달았다'') mixed with precise technical vocabulary (model names like multilingual-e5-small, sqlite-vec, FTS5 stated exactly, not vaguely). Confident but not boastful; treats failure as the interesting part of the story rather than something to hide.', 'Bold for key concept phrases and problem statements, inline code spans for technical identifiers, numbered/bulleted lists for parallel problems or features, embedded diagrams/screenshots illustrating architecture evolution, a blockquote to isolate the article''s core premise, and a comparison table as the climax before the closing reflection — all devices aimed at letting an engineer skim the shape of the argument without reading every sentence.', 'Grounds abstract technical decisions in company-internal concrete nouns the outside reader wouldn''t know but instantly senses are real — e.g. ''용차'' (rental vehicle) and ''샛별배송'' (Kurly''s dawn-delivery service) used as worked examples inside a generic RAG/retrieval discussion. This makes an otherwise generic ML architecture post feel like a first-hand internal case study, not a tutorial copied from docs.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://helloworld.kurly.com/')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Korean sans-serif system font stack throughout, with a clear size/weight step between card headlines (bold, larger) and metadata (author, category, date) rendered small and muted below. Headlines are dense, occasionally two-line, left-aligned within cards rather than centered.', 'Light, neutral background (white/off-white) with color reserved almost entirely for the small category badges — this keeps the grid visually calm and photo/thumbnail-driven rather than text-cluttered, and lets the badge color act as the only real color-coding signal for filtering by topic. Layout is a responsive multi-column card grid with numbered pagination at the bottom (not infinite scroll), plus a persistent top filter bar (전체/기술/AI-데이터/프로덕트) that acts as the primary navigation device.', 'Homepage is a strict image-led card grid: each card leads with a thumbnail/cover image, then a color-coded category badge (기술 / AI·데이터 / 프로덕트), then the bold headline, then a one-line description, then author + date in small gray text — a consistent top-to-bottom scan path repeated identically across every card so the eye learns the pattern once and then scans purely for headline text on subsequent passes.', 'The category-badge-as-color-key system: instead of differentiating sections with separate colors/layouts, the entire site uses one uniform card template and lets a single small colored badge silently encode topic, so the grid reads as one continuous, browsable feed regardless of team or subject — a deliberately understated, engineering-blog-appropriate design choice that prioritizes content scanability over visual flourish.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://helloworld.kurly.com/')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), 'AI에게 도메인을 가르치다 두 번 갈아엎은 이야기 — LLM Wiki + RAG 혼합기'), (( SELECT id FROM b), '현관문에도 얼굴이 있다: 배송 완료 사진 기반 On-device 오배송 탐지 시스템'), (( SELECT id FROM b), 'AI 에이전트 15개를 동시에 굴리는 법 — AI 병렬 오케스트레이션 실전 운용기'), (( SELECT id FROM b), 'AI 토큰 사용량 전사 1위 개발자가 148,000번의 대화에서 배운 것');

WITH b AS (
  INSERT INTO wordpress_blogs (name, url, region, accessible)
  VALUES ('야놀자클라우드 Tech Blog (Yanolja Tech Blog on Medium)', 'https://medium.com/yanoljacloud-tech', 'Korea', true)
  ON CONFLICT (url) DO UPDATE SET name = EXCLUDED.name, accessible = EXCLUDED.accessible
  RETURNING id
)
INSERT INTO wordpress_writing_findings (blog_id, headline_pattern, opening_hook, structure, paragraph_style, tone, formatting_devices, distinctive_technique)
SELECT id, 'Two-tier title+subtitle, always split into an abstract/aspirational H1 noun phrase (e.g. ''성장의 선순환을 추구하는 문화'') paired with a concrete, grounding H2 subtitle that names the team and promises the reader an experience (''~팀에서 경험할 수 있어요/가능해요''). This exact recruiting-flavored template repeats across culture posts. Technical posts instead use a functional Tool+Verb pattern: ''[Tech]로 [작업]하기'' (Facebook Prophet으로 미래 지표 예측하기; AWS Glue로 만들어 보는 간단 배치 시스템) or a curiosity question (''java 코드는 어떻게 자동으로 만들어질까''), split into numbered parts (1/2, 2/2) for long technical topics.', 'Nearly every post opens with a direct, warm greeting to the reader in spoken register (''안녕하세요. 오늘은...'') that frames the piece as a conversation/interview rather than a report, then immediately states what curiosity it will satisfy (''그동안 궁금했던 QA 업무와 팀 문화에 대해 많은 이야기를 듣고 왔습니다''). Culture pieces add a wink of self-aware humor breaking the promotional register (''하마터면 저도 깜빡 팀을 옮길 뻔했어요... 어쩔 수 없어요. (찡긋)'').', 'Long-form culture/interview pieces are built as a sequence of mini-chapters, one per interviewee, each opened by a bold pull-quote blockquote (the interviewee''s most quotable line) immediately followed by a portrait photo, then an h3 subheading, then 3-5 body paragraphs, then a separator rule before the next speaker. Each speaker''s first paragraph opens with a bolded self-introduction sentence (''안녕하세요. 저는 QA 엔지니어 김지민입니다.''). The article closes with a bolded, hyperlinked job-posting call-to-action (''> 야놀자클라우드 QA 엔지니어 / 테스트 엔지니어 채용''). Technical posts instead follow a linear problem→approach→code→result structure.', 'Medium-length paragraphs (4-7 sentences), long compound sentences typical of spoken-style Korean essay writing, mixing -해요체 (친근한 구어체) with occasional -습니다체 for authority. Rhythm relies on subheadings and pull-quotes rather than short punchy lines — this is unhurried, magazine-style pacing, not listicle pacing.', 'Warm, humble-brag, colleague-to-colleague testimonial tone; reads like employer branding dressed as journalism. Confident and specific about technical/organizational detail, but consistently softened with polite endings and small asides.', 'Pull-quote blockquotes, horizontal separators between sections/speakers, h3 subheads per theme, bold used sparingly and purposefully (only for self-intro sentences and the closing job-link CTA), inline tag list at article footer (Yanolja Cloud, QA, 야놀자 클라우드 조직문화, etc.) for topical scanning.', 'Turning each interview subject''s key quote into a visual mini-headline (blockquote + portrait photo) rather than relying on generic subheads — this makes a single long article scannable like a multi-story spread, and doubles as social-proof marketing (letting employees ''sell'' the team in their own words) rather than an abstract editorial voice.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://medium.com/yanoljacloud-tech')
INSERT INTO wordpress_design_findings (blog_id, typography, color_and_layout, visual_hierarchy, distinctive_element)
SELECT id, 'Standard Medium serif (Georgia-like) for H1 titles and body copy, creating a literary/editorial feel; sans-serif for UI chrome (nav, bylines, tags). Clear two-level heading hierarchy: large serif H1 title, smaller grey-toned H2 subtitle directly beneath it, then h3s within the body for section breaks — the subtitle is visually secondary but semantically load-bearing (it''s where the ''who this is for'' payoff lives).', 'Publication header is minimal: logo mark, publication name, one-line mission tagline, follower count, editor badge, and a horizontal pill/tab bar (NEWS / TECH / PRODUCT / CULTURE / CAREER / Y FLUX) that lets visitors filter by content type before ever scrolling the feed. Below that, a plain vertical card list — thumbnail image, H2 headline, H3 subtitle, and a byline row (avatar · name · date · read time) — Medium''s default light-canvas, high-whitespace card layout with no custom brand color system visible outside the publication logo/tagline block.', 'Byline metadata is deliberately compressed into one scannable line (avatar + name + dot + date + dot + read-time) so the eye can skip straight from headline to ''is this relevant/current'' in one glance. Inside articles, the portrait photo + pull-quote pairing acts as a secondary hierarchy layer above the h3 subheads, letting skimmers reconstruct the whole article''s argument just by reading the blockquotes down the page.', 'The interviewee pull-quote-plus-portrait block that opens every speaker section — it functions simultaneously as a mini-headline, a trust signal (a real named face and quote, not a stock photo), and a scroll-anchor, turning a text-heavy HR/culture post into something closer to a magazine profile spread.' FROM b;

WITH b AS (SELECT id FROM wordpress_blogs WHERE url = 'https://medium.com/yanoljacloud-tech')
INSERT INTO wordpress_headline_examples (blog_id, headline_text) VALUES (( SELECT id FROM b), '개인, 조직, 제품 성장의 선순환을 추구하는 문화 — 야놀자클라우드 QA 팀에서 경험할 수 있어요.'), (( SELECT id FROM b), '야놀자클라우드가 Y FLUX PMS를 만든 이유는? — 왜 필요한지 알면, 안 만들 수 없어요.'), (( SELECT id FROM b), '주도적으로 데이터 플레이를 이끄는 전문가 되기 — 야놀자클라우드 Data Engineering 팀에서는 가능해요.'), (( SELECT id FROM b), 'Facebook Prophet으로 미래 지표 예측하기 — 다섯 줄로 만나는 미래'), (( SELECT id FROM b), '슬기로운 Senior 개발자 생활 — 야놀자클라우드 구성원 살펴보기 1탄 — Back-end Engineer');

